// Website Ingestion Config — INDUSTRIE sector
// Target: Pinecone index 'website-sectors-jina-1024', namespace 'industrie'
// DO NOT use rag-data-ingestion workflows (those are for benchmarks only)

const config = {
  sector: 'industrie',
  namespace: 'industrie',
  pinecone_index: 'website-sectors-jina-1024',
  jina_model: 'jina-embeddings-v3',
  chunk_size: 512,
  chunk_overlap: 50,
  late_chunking: true,  // Late Chunking (arXiv:2409.04701) — +10-12% retrieval
  datasets: ["manufacturing_qa", "ragbench"],
  hf_ids: ["thesven/manufacturing-qa-gpt4o", "rungalileo/ragbench"],
  max_docs_per_dataset: 1000,  // Website demo: 1000 docs per dataset
  batch_size: 50
};

return [{ json: config }];

// Download industrie datasets from HuggingFace
// This node calls the HuggingFace API to get dataset samples
const config = $json;
const results = [];

for (const hf_id of config.hf_ids) {
  const url = `https://datasets-server.huggingface.co/first-rows?dataset=${encodeURIComponent(hf_id)}&config=default&split=train&offset=0&length=${config.max_docs_per_dataset}`;
  // Note: Actual download happens via HTTP Request node below
  results.push({
    hf_id: hf_id,
    download_url: url,
    sector: config.sector,
    namespace: config.namespace
  });
}

return results.map(r => ({ json: r }));

// Chunk documents for industrie — Late Chunking enabled
const response = $json;
const rows = response.rows || [];
const chunks = [];

for (let i = 0; i < rows.length; i++) {
  const row = rows[i].row || rows[i];
  // Extract text from common field names
  const text = row.question || row.text || row.content || row.context || 
               row.passage || row.answer || JSON.stringify(row).substring(0, 1000);

  if (!text || text.length < 20) continue;

  // Simple chunking (512 tokens ≈ 2000 chars)
  const chunkSize = 2000;
  const overlap = 200;

  for (let start = 0; start < text.length; start += chunkSize - overlap) {
    const chunk = text.substring(start, start + chunkSize);
    if (chunk.length < 50) continue;

    chunks.push({
      id: `industrie-${i}-${chunks.length}`,
      text: chunk,
      sector: 'industrie',
      namespace: 'industrie',
      metadata: {
        source: $('HTTP: Download Dataset').item?.json?.hf_id || 'unknown',
        chunk_index: chunks.length,
        sector: 'industrie',
        pipeline: 'website-ingestion'
      }
    });
  }
}

return chunks.map(c => ({ json: c }));

// Summary of ingestion for industrie
return [{
  json: {
    sector: 'industrie',
    namespace: 'industrie',
    pinecone_index: 'website-sectors-jina-1024',
    status: 'completed',
    timestamp: new Date().toISOString(),
    note: 'Website sector ingestion — distinct from rag-data-ingestion benchmarks'
  }
}];
